import { GoogleGenAI, Type } from "@google/genai";
import { MarketResearchResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are a Senior Market Research Analyst, Performance Marketing Strategist, Consumer Psychology Expert, and Funnel Architect specialized in Bangladesh E-commerce ecosystem.
Analyze the given product name for the Bangladesh market. 
Assume realistic Bangladesh market behavior (dominant Facebook usage, high mobile penetration, COD preference, value-conscious but status-seeking urban middle class).
Avoid generic advice. Think like a performance marketer spending real money.
Prioritize profitability over vanity metrics. 
The output language must be Bengali (Bangladesh) for content parts (copies, hooks, descriptions), while maintaining the JSON structure.
Be practical and persuasive.`;

export const analyzeProduct = async (productName: string): Promise<MarketResearchResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Analyze this product: ${productName}. Follow the requested output schema strictly. Generate all marketing copies, hooks, and descriptions in Bengali.`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          product_market_fit: {
            type: Type.OBJECT,
            properties: {
              core_problem: { type: Type.STRING },
              urgency_level: { type: Type.STRING },
              demand_type: { type: Type.STRING },
              cultural_relevance: { type: Type.STRING },
              seasonality: { type: Type.STRING },
              market_fit_score: { type: Type.NUMBER },
              price_sensitivity: { type: Type.STRING },
            },
            required: ["core_problem", "urgency_level", "demand_type", "cultural_relevance", "seasonality", "market_fit_score", "price_sensitivity"],
          },
          competition_analysis: {
            type: Type.OBJECT,
            properties: {
              estimated_active_sellers: { type: Type.STRING },
              avg_daily_sales_per_seller: { type: Type.STRING },
              price_range_bdt: { type: Type.STRING },
              competition_type: { type: Type.STRING },
              ad_saturation: {
                type: Type.OBJECT,
                properties: {
                  facebook_instagram: { type: Type.NUMBER },
                  google_ads: { type: Type.NUMBER },
                  marketplaces: { type: Type.NUMBER },
                },
                required: ["facebook_instagram", "google_ads", "marketplaces"],
              },
              entry_difficulty: { type: Type.STRING },
            },
            required: ["estimated_active_sellers", "avg_daily_sales_per_seller", "price_range_bdt", "competition_type", "ad_saturation", "entry_difficulty"],
          },
          customer_avatars: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                avatar_name: { type: Type.STRING },
                age_range: { type: Type.STRING },
                gender: { type: Type.STRING },
                location: { type: Type.STRING },
                income_level: { type: Type.STRING },
                pain_points: { type: Type.ARRAY, items: { type: Type.STRING } },
                hidden_fears: { type: Type.ARRAY, items: { type: Type.STRING } },
                desired_transformation: { type: Type.STRING },
                buying_objections: { type: Type.ARRAY, items: { type: Type.STRING } },
                purchase_triggers: { type: Type.ARRAY, items: { type: Type.STRING } },
              },
              required: ["avatar_name", "age_range", "gender", "location", "income_level", "pain_points", "hidden_fears", "desired_transformation", "buying_objections", "purchase_triggers"],
            },
          },
          customer_journey: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stage: { type: Type.STRING },
                user_mindset: { type: Type.STRING },
                best_content_type: { type: Type.STRING },
                recommended_platforms: { type: Type.ARRAY, items: { type: Type.STRING } },
                ad_objective: { type: Type.STRING },
              },
              required: ["stage", "user_mindset", "best_content_type", "recommended_platforms", "ad_objective"],
            },
          },
          funnel_content_strategy: {
            type: Type.OBJECT,
            properties: {
              cold_audience: {
                type: Type.OBJECT,
                properties: {
                  hooks: { type: Type.ARRAY, items: { type: Type.STRING } },
                  content_angles: { type: Type.ARRAY, items: { type: Type.STRING } },
                  best_placements: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["hooks", "content_angles", "best_placements"],
              },
              warm_audience: {
                type: Type.OBJECT,
                properties: {
                  authority_building_angles: { type: Type.ARRAY, items: { type: Type.STRING } },
                  social_proof_types: { type: Type.ARRAY, items: { type: Type.STRING } },
                  best_placements: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["authority_building_angles", "social_proof_types", "best_placements"],
              },
              hot_audience: {
                type: Type.OBJECT,
                properties: {
                  offer_framing: { type: Type.ARRAY, items: { type: Type.STRING } },
                  urgency_scarcity: { type: Type.ARRAY, items: { type: Type.STRING } },
                  risk_reversal: { type: Type.ARRAY, items: { type: Type.STRING } },
                  best_placements: { type: Type.ARRAY, items: { type: Type.STRING } },
                },
                required: ["offer_framing", "urgency_scarcity", "risk_reversal", "best_placements"],
              },
            },
            required: ["cold_audience", "warm_audience", "hot_audience"],
          },
