                    body: { type: Type.STRING },
                    cta: { type: Type.STRING },
                  },
                  required: ["hook", "body", "cta"],
                },
              },
              warm_audience: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    body: { type: Type.STRING },
                    cta: { type: Type.STRING },
                  },
                  required: ["body", "cta"],
                },
