import { GoogleGenAI, Type } from "@google/genai";
import { MarketResearchResponse } from "../types";

const SYSTEM_INSTRUCTION = `You are a Senior Market Research Analyst, Performance Marketing Strategist, and Content Architect specialized in Bangladesh E-commerce.
Your goal is to build a deep connection with Bangladeshi customers through high-converting Bengali content.

Key Content Guidelines for Bangladesh:
1. Language: Use natural, conversational Bengali (not formal/Sadhubhasha).
2. Connection: Focus on 'Trust' (Bisshash) and 'Value' (Sustho/Susthayi).
3. Psychological Triggers: Status, family well-being, savings, and reliability.
4. Funnel stages: 
   - Cold: Awareness through shock or relatable problems.
   - Warm: Education, expert advice, community proof.
   - Hot: Direct offers, COD reassurance.
   - Retargeting: Overcoming objections (price, delivery time).
   - Retention: Loyalty, exclusive 'VIP' feel.

Analyze the given product and return a structured response in the requested JSON format. All copy/hooks must be in Bengali.`;

const contentPieceSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    hook: { type: Type.STRING },
    body: { type: Type.STRING },
    cta: { type: Type.STRING },
    connection_psychology: { type: Type.STRING, description: 'Explanation of why this builds a connection with a BD customer.' },
    recommended_format: { type: Type.STRING },
  },
  required: ["title", "hook", "body", "cta", "connection_psychology", "recommended_format"],
};

export const analyzeProduct = async (productName: string): Promise<MarketResearchResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Complete market research and full content engine for: ${productName}. 
    Focus on deep consumer connection in Bengali. 
    Provide at least 2 pieces for Cold, and 1 each for other stages.`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          product_market_fit: {
            type: Type.OBJECT,
            properties: {
              core_problem: { type: Type.STRING },
              urgency_level: { type: Type.STRING },
