                  </div>
                </div>
              </div>
            </section>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
               <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100">
                <h3 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-4">
                  <div className="w-10 h-10 bg-emerald-500 text-white rounded-xl flex items-center justify-center"><i className="fas fa-rocket"></i></div>
                  সফল হওয়ার টিপস
                </h3>
                <div className="space-y-5">
                  {decision.optimization_requirements.map((req, i) => (
                    <div key={i} className="flex items-start gap-4 text-slate-700 font-bold border-b border-slate-50 pb-5 last:border-0"><i className="fas fa-check-circle text-emerald-500 mt-1"></i><p>{req}</p></div>
                  ))}
                </div>
              </div>
              <div className="bg-white rounded-3xl p-8 shadow-xl border border-slate-100">
                <h3 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-4">
                  <div className="w-10 h-10 bg-rose-500 text-white rounded-xl flex items-center justify-center"><i className="fas fa-triangle-exclamation"></i></div>
