                    <div key={i} className="flex items-start gap-5 p-5 bg-rose-50 rounded-2xl border border-rose-100"><div className="w-8 h-8 bg-rose-500 text-white rounded-full flex items-center justify-center text-xs font-black shrink-0">!</div><p className="text-base text-rose-900 font-black">{risk}</p></div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        );

      case 'market':
        return (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="bg-white rounded-3xl p-10 shadow-xl border border-slate-100">
                <h3 className="text-2xl font-black mb-8">মার্কেট ফিট রিসার্চ</h3>
                <div className="space-y-8">
                  <div className="p-6 bg-slate-50 rounded-2xl"><p className="text-[10px] font-black text-slate-400 mb-2 uppercase">প্রধান সমস্যা</p><p className="text-slate-900 font-black text-xl">{pmf.core_problem}</p></div>
                  <div className="grid grid-cols-2 gap-6">
                    <div className="p-5 border border-slate-200 rounded-2xl"><p className="text-[10px] text-slate-400 font-black mb-2 uppercase">জরুরিতা</p><p className="text-slate-900 font-black text-lg">{pmf.urgency_level}</p></div>
                    <div className="p-5 border border-slate-200 rounded-2xl"><p className="text-[10px] text-slate-400 font-black mb-2 uppercase">চাহিদা</p><p className="text-slate-900 font-black text-lg">{pmf.demand_type}</p></div>
