              </div>
              <div className="bg-white rounded-3xl p-10 shadow-xl border border-slate-100">
                <h3 className="text-2xl font-black mb-8">কম্পিটিশন ও স্যাচুরেশন</h3>
                <div className="h-64 mb-8">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={[
                      { name: 'FB/IG', value: comp.ad_saturation.facebook_instagram },
                      { name: 'Google', value: comp.ad_saturation.google_ads },
                      { name: 'Markets', value: comp.ad_saturation.marketplaces },
                    ]} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                      <XAxis type="number" hide />
                      <YAxis dataKey="name" type="category" width={80} tick={{ fontSize: 12, fontWeight: 800 }} />
                      <Tooltip />
                      <Bar dataKey="value" radius={[0, 10, 10, 0]} barSize={36}>
                        <Cell fill="#10b981" /><Cell fill="#3b82f6" /><Cell fill="#f59e0b" />
                      </Bar>
