                  <p className="text-sm text-slate-500 font-black uppercase mb-10">{avatar.age_range} • {avatar.gender}</p>
                  <div className="p-6 bg-rose-50 rounded-2xl border border-rose-100 mb-6"><h5 className="text-[11px] font-black text-rose-600 uppercase mb-3">প্রধান পেইন পয়েন্টসমূহ</h5><ul className="text-sm space-y-2 font-black">{avatar.pain_points.slice(0, 3).map((p, i) => <li key={i}>/ {p}</li>)}</ul></div>
                  <div className="p-6 bg-emerald-50 rounded-2xl border border-emerald-100"><h5 className="text-[11px] font-black text-emerald-600 uppercase mb-2">প্রত্যাশিত রেজাল্ট</h5><p className="text-sm font-black">"{avatar.desired_transformation}"</p></div>
                </div>
