            </div>
          </div>
        );

      case 'competitors':
        return (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="max-w-3xl mx-auto mb-16 text-center">
              <div className="inline-block px-4 py-1.5 bg-violet-100 text-violet-600 text-[10px] font-black rounded-full uppercase tracking-widest mb-4">Competitor Intelligence</div>
              <h3 className="text-4xl font-black text-slate-900 mb-4">লাইভ প্রতিযোগী রিসার্চ</h3>
              <p className="text-slate-500 text-lg font-bold">মার্কেটের অন্যান্য ব্র্যান্ডগুলো বর্তমানে কী ধরণের অ্যাড চালাচ্ছে এবং কোন স্ট্র্যাটেজিতে তারা সফল হচ্ছে তা এখানে দেখুন।</p>
