               <div className="space-y-8">
                  <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-xl">
                    <h4 className="text-lg font-black mb-6 flex items-center gap-3">
                      <i className="fas fa-trophy text-amber-400"></i>
