                    </h4>
                    <div className="space-y-4">
                      {compRes.winning_creative_elements.map((el, i) => (
                        <div key={i} className="flex items-center gap-4 p-3 bg-white/5 rounded-xl border border-white/10 group hover:bg-white/10 transition-all">
                          <i className="fas fa-check-circle text-emerald-400 text-xs"></i>
                          <p className="text-sm font-bold">{el}</p>
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="bg-white rounded-3xl p-8 border border-slate-100 shadow-sm">
                    <h4 className="text-lg font-black text-slate-800 mb-6">Live Ad Libraries</h4>
                    <div className="space-y-3">
                      <a href={compRes.ad_library_links.meta} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-4 bg-blue-50 text-blue-700 rounded-2xl hover:bg-blue-100 transition-all group">
                         <div className="flex items-center gap-3 font-black text-sm"><i className="fab fa-facebook-square text-xl"></i> Meta Ad Library</div>
                         <i className="fas fa-external-link-alt text-xs opacity-0 group-hover:opacity-100 transition-all"></i>
                      </a>
                      <a href={compRes.ad_library_links.tiktok} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-4 bg-slate-900 text-white rounded-2xl hover:bg-slate-800 transition-all group">
                         <div className="flex items-center gap-3 font-black text-sm"><i className="fab fa-tiktok text-xl"></i> TikTok Ads Center</div>
                         <i className="fas fa-external-link-alt text-xs opacity-0 group-hover:opacity-100 transition-all"></i>
                      </a>
                      <a href={compRes.ad_library_links.google} target="_blank" rel="noopener noreferrer" className="flex items-center justify-between p-4 bg-slate-50 text-slate-700 rounded-2xl hover:bg-slate-100 transition-all group border border-slate-100">
                         <div className="flex items-center gap-3 font-black text-sm"><i className="fab fa-google text-xl text-red-500"></i> Google Transparency</div>
                         <i className="fas fa-external-link-alt text-xs opacity-0 group-hover:opacity-100 transition-all"></i>
                      </a>
                    </div>
                  </div>
               </div>
            </div>
          </div>
        );

      case 'cold':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="max-w-3xl mx-auto mb-16 text-center">
              <div className="inline-block px-4 py-1.5 bg-indigo-100 text-indigo-600 text-[10px] font-black rounded-full uppercase tracking-widest mb-4">Top of Funnel (ToFU)</div>
              <h3 className="text-4xl font-black text-slate-900 mb-4">কোল্ড অডিয়েন্স স্ট্র্যাটেজি</h3>
              <p className="text-slate-500 text-lg font-bold">নতুন কাস্টমারদের মনোযোগ কাড়ার জন্য হুক এবং রেডি বিজ্ঞাপন।</p>
            </div>
            {copies.cold_audience.map((piece) => renderContentPiece(piece, 'bg-indigo-600', 'cold_audience'))}
          </div>
        );

      case 'warm':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
             <div className="max-w-3xl mx-auto mb-16 text-center">
              <h3 className="text-4xl font-black text-slate-900 mb-4">ওয়ার্ম অডিয়েন্স ট্রাস্ট ইঞ্জিন</h3>
              <p className="text-slate-500 text-lg font-bold">যারা পণ্যটি নিয়ে ভাবছে কিন্তু দ্বিধায় আছে, তাদের বিশ্বাস অর্জন করতে প্রয়োজনীয় কন্টেন্ট।</p>
            </div>
            {copies.warm_audience.map((piece) => renderContentPiece(piece, 'bg-orange-600', 'warm_audience'))}
          </div>
        );

      case 'hot':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="max-w-3xl mx-auto mb-16 text-center">
              <h3 className="text-4xl font-black text-slate-900 mb-4">হট অডিয়েন্স কনভার্সন প্যাক</h3>
              <p className="text-slate-500 text-lg font-bold">সরাসরি বিক্রির জন্য জোরালো অফার এবং রেডি বিজ্ঞাপন।</p>
            </div>
            {copies.hot_audience.map((piece) => renderContentPiece(piece, 'bg-rose-600', 'hot_audience'))}
          </div>
        );

      case 'retargeting':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="max-w-3xl mx-auto mb-16 text-center">
              <h3 className="text-4xl font-black text-slate-900 mb-4">রি-টার্গেটিং অ্যাড ইঞ্জিন</h3>
              <p className="text-slate-500 text-lg font-bold">ফিরে আসার কন্টেন্ট।</p>
            </div>
            {copies.retargeting.map((piece) => renderContentPiece(piece, 'bg-emerald-600', 'retargeting'))}
          </div>
        );

      case 'retention':
        return (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
            <div className="max-w-3xl mx-auto mb-16 text-center">
              <h3 className="text-4xl font-black text-slate-900 mb-4">কাস্টমার রিটেনশন প্যাক</h3>
              <p className="text-slate-500 text-lg font-bold">পুনরায় বিক্রির জন্য আইডিয়া।</p>
            </div>
            {copies.retention.map((piece) => renderContentPiece(piece, 'bg-pink-600', 'retention'))}
          </div>
        );
      default: return null;
    }
  };

  return (
    <div className="space-y-8 pb-20 max-w-7xl mx-auto">
      <nav className="flex flex-wrap justify-center gap-3 p-2 bg-white rounded-3xl shadow-xl border border-slate-100 sticky top-20 z-40 overflow-x-auto no-scrollbar backdrop-blur-md bg-white/90">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-2.5 px-6 py-4 rounded-2xl text-sm font-black transition-all duration-300 whitespace-nowrap shadow-sm border ${
              activeTab === tab.id
                ? `${tab.color} text-white shadow-lg border-transparent scale-105`
                : 'text-slate-500 bg-slate-50 border-slate-100 hover:bg-white hover:text-slate-900'
            }`}
          >
            <i className={`fas ${tab.icon}`}></i>
            <span>{tab.label}</span>
          </button>
        ))}
      </nav>
      <div className="min-h-[600px] pt-6 px-4">
        {renderContent()}
      </div>
    </div>
  );
};

export default AnalysisDashboard;

export interface ProductMarketFit {
  core_problem: string;
  urgency_level: 'High' | 'Medium' | 'Low';
  demand_type: 'Impulse' | 'Considered' | 'Necessity';
  cultural_relevance: string;
  seasonality: string;
  market_fit_score: number;
  price_sensitivity: 'Low' | 'Medium' | 'High';
}

export interface AdSaturation {
  facebook_instagram: number;
  google_ads: number;
  marketplaces: number;
}

export interface CompetitionAnalysis {
  estimated_active_sellers: 'Low' | 'Medium' | 'High';
  avg_daily_sales_per_seller: 'Low' | 'Medium' | 'High';
  price_range_bdt: string;
  competition_type: 'Brand-led' | 'Commodity-led' | 'Mixed';
  ad_saturation: AdSaturation;
  entry_difficulty: 'Easy' | 'Moderate' | 'Hard';
}

export interface CompetitorAd {
  platform: 'Meta' | 'TikTok' | 'YouTube' | 'Google';
