  hidden_fears: string[];
  desired_transformation: string;
  buying_objections: string[];
  purchase_triggers: string[];
}

export interface AdVariation {
  headline: string;
  hook: string;
  body: string;
  cta: string;
}

export interface ContentPiece {
  id: string;
  title: string;
  hooks: string[];
  ideas: string[];
