  const PremiumLock: React.FC<{ title: string; proOnly?: boolean }> = ({ children, title, proOnly = false }) => {
    // If Guest -> must sign up.
    // If Free -> can see Free features (Strategy/Success).
    // If Pro -> can see everything.

    // Gating logic:
    const isFreeSection = title === "VERDICT_HERO" || title === "SUCCESS_FACTORS";
    const canSee = isPro || (isFree && isFreeSection);

    if (canSee) return <>{children}</>;

    return (
      <div className="relative group mb-12">
        <div className="filter blur-md select-none pointer-events-none opacity-40 overflow-hidden max-h-96">
          {children}
        </div>
        <div className="absolute inset-0 z-10 flex flex-col items-center justify-center p-10 bg-white/40 backdrop-blur-[4px] rounded-[3.5rem] border border-white/50 transition-all shadow-sm">
          <div className="w-20 h-20 bg-slate-950 text-white rounded-[2rem] flex items-center justify-center mb-6 shadow-2xl">
            <i className={`fas ${isGuest ? 'fa-user-lock' : 'fa-lock'} text-2xl`}></i>
          </div>
          <h4 className="text-2xl font-black text-slate-950 mb-4 text-center">
            {isGuest ? 'Sign Up to Unlock Strategy' : 'Upgrade to Pro'}
          </h4>
          <p className="text-base text-slate-600 font-bold mb-8 text-center max-w-sm">
            {isGuest 
              ? 'ব্যবসায়িক পর্যালোচনা ও পূর্ণাঙ্গ স্ট্র্যাটেজি দেখতে ফ্রিতে সাইন আপ করুন।' 
              : 'মার্কেট কম্পিটিশন, বাজেট বণ্টন এবং সিক্রেট টিপস দেখতে প্রিমিয়াম মেম্বার হোন।'}
          </p>
          {isGuest ? (
            <button onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} className="px-10 py-5 bg-emerald-600 text-white font-black rounded-[1.5rem] hover:bg-emerald-700 transition-all shadow-2xl">
              Sign Up Now (Free)
            </button>
          ) : (
            <button onClick={() => { setActiveTab('strategy'); setTimeout(() => { document.getElementById('pricing')?.scrollIntoView({ behavior: 'smooth' }); }, 100); }} className="px-10 py-5 bg-slate-900 text-white font-black rounded-[1.5rem] hover:bg-slate-800 transition-all shadow-2xl">
              Upgrade Account
            </button>
          )}
        </div>
      </div>
    );
  };

  const renderCompetitorAd = (ad: CompetitorAd, index: number) => (
    <div key={index} className="bg-white rounded-[2.5rem] p-8 shadow-xl border border-slate-100 flex flex-col md:flex-row gap-8 items-center group hover:shadow-2xl transition-all">
      <div className="w-20 h-20 rounded-3xl bg-slate-900 text-white flex items-center justify-center text-3xl shadow-lg shrink-0 transition-transform group-hover:scale-110">
        <i className={`fab fa-${ad.platform.toLowerCase()}`}></i>
      </div>
      <div className="flex-grow w-full">
        <div className="flex flex-col sm:flex-row justify-between items-start mb-4 gap-3">
          <div>
            <h4 className="text-xl font-black text-slate-900">{ad.brand_name}</h4>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{ad.ad_type} • {ad.estimated_duration}</p>
          </div>
          <div className="px-5 py-2.5 bg-emerald-50 text-emerald-600 rounded-2xl text-[10px] font-black uppercase tracking-wider border border-emerald-100 shrink-0">
            {ad.performance_score}/10 Performance
          </div>
        </div>
        <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
           <p className="text-sm text-slate-600 font-bold leading-relaxed italic">"{ad.strategy_insight}"</p>
        </div>
      </div>
    </div>
  );

  const renderStrategyTab = () => {
    const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];
    const pieData = decision.marketing_channels.map(c => ({ name: c.channel, value: c.allocation_percentage }));

    return (
      <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
        {/* FREE: Verdict Hero Banner */}
        <PremiumLock title="VERDICT_HERO">
          <section className="relative overflow-hidden rounded-[4rem] bg-gradient-to-br from-slate-900 via-slate-950 to-indigo-950 text-white p-12 lg:p-20 shadow-3xl">
            <div className="absolute top-0 right-0 w-1/2 h-full opacity-5 pointer-events-none">
              <i className="fas fa-chess-king text-[20rem] transform translate-x-20 translate-y-20"></i>
            </div>

            <div className="relative z-10 flex flex-col lg:flex-row items-center gap-16">
              <div className={`shrink-0 w-72 h-72 rounded-[4.5rem] rotate-3 flex flex-col items-center justify-center border-4 border-white/20 shadow-2xl backdrop-blur-sm ${decision.verdict === 'YES' ? 'bg-emerald-500/90' : 'bg-rose-500/90'}`}>
                <div className="-rotate-3 flex flex-col items-center">
                  <span className="text-[10px] uppercase font-black tracking-[0.2em] opacity-80 mb-3">Strategy Verdict</span>
                  <span className="text-9xl font-black tracking-tighter">{decision.verdict}</span>
                </div>
              </div>

              <div className="flex-grow max-w-full lg:max-w-4xl">
                <h2 className="text-3xl lg:text-5xl font-black mb-10 leading-[1.2] text-transparent bg-clip-text bg-gradient-to-r from-white to-slate-400">ব্যবসায়িক পর্যালোচনা ও <br/> <span className="text-emerald-400">পূর্ণাঙ্গ স্ট্র্যাটেজি</span></h2>
                <div className="p-10 bg-white/5 border border-white/10 rounded-[2.5rem] backdrop-blur-md">
                  <p className="text-xl lg:text-2xl font-bold italic text-slate-100 leading-relaxed break-words whitespace-pre-wrap">
                    "{decision.decision_reasoning}"
                  </p>
                </div>
              </div>
            </div>

            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-10 relative z-10">
               <div className="bg-white/5 backdrop-blur-md p-10 rounded-[3rem] border border-white/10 shadow-xl">
                 <div className="flex items-center gap-5 mb-6">
                   <div className="w-14 h-14 rounded-2xl bg-emerald-500/20 flex items-center justify-center text-emerald-400 shadow-lg"><i className="fas fa-chart-line text-2xl"></i></div>
                   <p className="text-xs font-black uppercase text-emerald-400 tracking-widest">Niche Potential</p>
                 </div>
                 <p className="text-sm text-slate-300 font-bold leading-relaxed mb-6">{decision.niche_potential_description}</p>
                 <div className="text-4xl font-black text-white uppercase tracking-tighter">খুব ভালো</div>
               </div>

               <div className="bg-white/5 backdrop-blur-md p-10 rounded-[3rem] border border-white/10 shadow-xl">
                 <div className="flex items-center gap-5 mb-6">
                   <div className="w-14 h-14 rounded-2xl bg-blue-500/20 flex items-center justify-center text-blue-400 shadow-lg"><i className="fas fa-bullseye text-2xl"></i></div>
                   <p className="text-xs font-black uppercase text-blue-400 tracking-widest">Market Fit Score</p>
                 </div>
                 <p className="text-sm text-slate-300 font-bold leading-relaxed mb-6">{decision.market_fit_detailed_reason}</p>
                 <div className="text-5xl font-black text-white">{pmf.market_fit_score}<span className="text-2xl opacity-40 ml-2">/ 10</span></div>
               </div>

               <div className="bg-white/5 backdrop-blur-md p-10 rounded-[3rem] border border-white/10 shadow-xl">
                 <div className="flex items-center gap-5 mb-6">
                   <div className="w-14 h-14 rounded-2xl bg-amber-500/20 flex items-center justify-center text-amber-400 shadow-lg"><i className="fas fa-wallet text-2xl"></i></div>
                   <p className="text-xs font-black uppercase text-amber-400 tracking-widest">Starting Budget</p>
                 </div>
                 <p className="text-sm text-slate-300 font-bold leading-relaxed mb-6">{decision.budget_breakdown_detail}</p>
                 <div className="text-4xl font-black text-white tracking-tighter">৳{decision.starting_budget_bdt.toLocaleString()}</div>
               </div>
            </div>
          </section>
        </PremiumLock>

        {/* FREE: Success Factors */}
        <PremiumLock title="SUCCESS_FACTORS">
          <div className="bg-white rounded-[3.5rem] p-12 lg:p-16 shadow-xl border border-slate-100 overflow-hidden">
            <h3 className="text-3xl font-black text-slate-900 mb-12 flex items-center gap-5">
              <div className="w-16 h-16 bg-indigo-600 text-white rounded-[2rem] flex items-center justify-center shadow-xl shadow-indigo-100"><i className="fas fa-sliders-h text-xl"></i></div>
              মূল সফলতার নিয়ামকসমূহ (Success Factors)
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-16 gap-y-12">
              {decision.decision_factors.map((f, i) => (
                <div key={i} className="space-y-4 group">
                  <div className="flex justify-between items-center">
                    <span className="flex items-center gap-4 text-sm font-black text-slate-800 uppercase tracking-widest">
                       <div className={`w-4 h-4 rounded-full shadow-inner ${f.impact === 'Positive' ? 'bg-emerald-500' : f.impact === 'Negative' ? 'bg-rose-500' : 'bg-slate-300'}`}></div>
                       {f.factor}
                    </span>
                    <span className="text-lg font-black text-indigo-600">{f.score}%</span>
                  </div>
                  <div className="h-4 bg-slate-100 rounded-full overflow-hidden p-1 shadow-inner relative">
                    <div className={`h-full rounded-full transition-all duration-1000 ${f.impact === 'Positive' ? 'bg-gradient-to-r from-emerald-400 to-emerald-600' : f.impact === 'Negative' ? 'bg-gradient-to-r from-rose-400 to-rose-600' : 'bg-slate-400'}`} style={{ width: `${f.score}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </PremiumLock>

        {/* PRO GATED: Competition */}
        <PremiumLock title="মার্কেট কম্পিটিশন স্ট্যাটাস">
          <div className="bg-white rounded-[3.5rem] p-12 lg:p-16 shadow-xl border border-slate-100 overflow-hidden">
            <h3 className="text-3xl font-black text-slate-900 mb-12 flex items-center gap-5">
              <div className="w-16 h-16 bg-rose-500 text-white rounded-[2rem] flex items-center justify-center shadow-xl shadow-rose-100"><i className="fas fa-shield-alt text-xl"></i></div>
              মার্কেট কম্পিটিশন স্ট্যাটাস
            </h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8 mb-12">
              {[
                { label: 'প্রতিযোগিতার ধরন', val: comp.competition_type },
                { label: 'প্রাইস লেভেল', val: `৳${comp.price_range_bdt}` },
                { label: 'এন্ট্রি লেভেল', val: comp.entry_difficulty },
                { label: 'গড় চাহিদা', val: pmf.urgency_level }
              ].map((item, i) => (
                <div key={i} className="p-8 bg-slate-50 rounded-[2.5rem] border border-slate-100 text-center hover:bg-white hover:shadow-xl transition-all">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-3">{item.label}</p>
                  <p className="text-xl font-black text-slate-900">{item.val}</p>
                </div>
              ))}
            </div>
          </div>
        </PremiumLock>

        <PremiumLock title="বাজেট ও চ্যানেল বণ্টন">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="bg-white rounded-[3.5rem] p-12 shadow-xl border border-slate-100 lg:col-span-1">
              <h3 className="text-2xl font-black text-slate-900 mb-10">বাজেট বণ্টন</h3>
              <div className="h-64 mb-10">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie data={pieData} cx="50%" cy="50%" innerRadius={75} outerRadius={105} paddingAngle={10} dataKey="value" stroke="none">
                      {pieData.map((entry, index) => ( <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} /> ))}
                    </Pie>
                    <Tooltip contentStyle={{ borderRadius: '24px', border: 'none' }} />
                  </PieChart>
                </ResponsiveContainer>
              </div>
              <div className="space-y-4">
                {decision.marketing_channels.map((c, i) => (
                  <div key={i} className="flex flex-col gap-2 p-5 bg-slate-50 rounded-[2rem] border border-slate-100 hover:bg-white hover:shadow-md transition-all">
                    <div className="flex items-center justify-between font-black text-xs">
                      <span className="flex items-center gap-3"><div className="w-3 h-3 rounded-full" style={{backgroundColor: COLORS[i % COLORS.length]}}></div> {c.channel}</span>
                      <span className="text-indigo-600">{c.allocation_percentage}%</span>
                    </div>
                    <p className="text-[10px] text-slate-500 font-bold italic leading-relaxed">"{c.reason}"</p>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-indigo-950 rounded-[3.5rem] p-16 text-white shadow-2xl lg:col-span-2 relative overflow-hidden">
              <div className="absolute -bottom-20 -right-20 w-80 h-80 bg-indigo-500/20 rounded-full blur-[100px]"></div>
              <h3 className="text-3xl font-black mb-12 flex items-center gap-6">
                 <div className="w-16 h-16 bg-white/10 text-white rounded-[2rem] flex items-center justify-center border border-white/20 shadow-xl backdrop-blur-md">
                    <i className="fas fa-graduation-cap text-xl"></i>
                 </div>
                 সফল উদ্যোক্তা হওয়ার সিক্রেট টিপস
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-10 relative z-10">
                {decision.entrepreneur_advice.map((advice, i) => (
                  <div key={i} className="p-8 bg-white/5 rounded-[2.5rem] border border-white/10 hover:bg-white/10 transition-all group">
                    <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center text-xs font-black mb-6 shadow-xl group-hover:scale-110 transition-transform">{i+1}</div>
                    <p className="text-lg font-bold leading-relaxed text-slate-200 italic">"{advice}"</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </PremiumLock>

        <PremiumLock title="মার্কেট লিডার কম্পিটিটর">
          <div className="bg-white rounded-[3.5rem] p-16 shadow-2xl border border-slate-100">
            <div className="text-center mb-16">
              <h3 className="text-4xl font-black text-slate-900 mb-4">মার্কেট লিডার লিষ্ট (Top Competitors)</h3>
              <p className="text-slate-500 font-bold text-lg">এই ব্র্যান্ডগুলো বর্তমানে মার্কেটে ভালো করছে। আপনি আলাদাভাবে এদের রিসার্চ করতে পারেন।</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-10">
              {compRes.top_competitors.map((brand, i) => (
                <div key={i} className="p-10 bg-slate-50 rounded-[3rem] border border-slate-100 flex flex-col items-center justify-center text-center group hover:bg-white hover:shadow-2xl transition-all duration-500 transform hover:-translate-y-3">
                  <div className="w-20 h-20 rounded-[2.5rem] bg-gradient-to-br from-indigo-500 to-indigo-700 shadow-xl flex items-center justify-center mb-8 text-white font-black text-4xl shadow-indigo-100">
                    {brand.name.charAt(0)}
                  </div>
                  <p className="text-xl font-black text-slate-900 mb-6 break-words w-full">{brand.name}</p>
                  <div className="flex gap-4 items-center">
                     {brand.active_platforms.includes('facebook') && <i className="fab fa-facebook text-slate-300 group-hover:text-blue-600 transition-colors"></i>}
                     {brand.active_platforms.includes('instagram') && <i className="fab fa-instagram text-slate-300 group-hover:text-pink-600 transition-colors"></i>}
                     {brand.active_platforms.includes('youtube') && <i className="fab fa-youtube text-slate-300 group-hover:text-red-600 transition-colors"></i>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </PremiumLock>

        {/* Pricing for Non-Pro users */}
        {!isPro && <div id="pricing"><PricingSection /></div>}
      </div>
    );
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'strategy': return renderStrategyTab();
      case 'market':
        return (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="bg-white rounded-[3.5rem] p-12 shadow-xl border border-slate-100">
                <h3 className="text-3xl font-black mb-10">মার্কেট ফিট রিসার্চ</h3>
                <div className="space-y-10">
                  <div className="p-8 bg-slate-50 rounded-[2.5rem]"><p className="text-[10px] font-black text-slate-400 mb-3 uppercase tracking-widest">প্রধান সমস্যা</p><p className="text-slate-900 font-black text-2xl leading-snug">{pmf.core_problem}</p></div>
                  <div className="grid grid-cols-2 gap-8">
                    <div className="p-8 border border-slate-100 rounded-[2.5rem] text-center"><p className="text-[10px] text-slate-400 font-black mb-3 uppercase tracking-widest">জরুরিতা</p><p className="text-slate-900 font-black text-xl">{pmf.urgency_level}</p></div>
                    <div className="p-8 border border-slate-100 rounded-[2.5rem] text-center"><p className="text-[10px] text-slate-400 font-black mb-3 uppercase tracking-widest">চাহিদা</p><p className="text-slate-900 font-black text-xl">{pmf.demand_type}</p></div>
                  </div>
                </div>
              </div>
              <div className="bg-white rounded-[3.5rem] p-12 shadow-xl border border-slate-100">
                <h3 className="text-3xl font-black mb-10">চ্যানেল স্যাচুরেশন</h3>
                <div className="h-72 mb-10">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={[
                      { name: 'FB/IG', value: comp.ad_saturation.facebook_instagram },
                      { name: 'Google', value: comp.ad_saturation.google_ads },
                      { name: 'Markets', value: comp.ad_saturation.marketplaces },
                    ]} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                      <XAxis type="number" hide />
                      <YAxis dataKey="name" type="category" width={80} tick={{ fontSize: 14, fontWeight: 900 }} />
                      <Tooltip />
                      <Bar dataKey="value" radius={[0, 15, 15, 0]} barSize={40}>
                        <Cell fill="#10b981" /><Cell fill="#3b82f6" /><Cell fill="#f59e0b" />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
            </div>
          </div>
        );

      case 'competitors':
        return (
          <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700">
             <div className="max-w-4xl mx-auto mb-16 text-center">
              <h3 className="text-5xl font-black text-slate-900 mb-6 leading-tight">লাইভ প্রতিযোগী রিসার্চ</h3>
              <p className="text-slate-500 text-xl font-bold">মার্কেটের অন্যান্য ব্র্যান্ডগুলো বর্তমানে কী ধরণের অ্যাড চালাচ্ছে তা এখানে দেখুন।</p>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
               <div className="lg:col-span-2 space-y-10">
                  {compRes.live_ad_trends.map((ad, i) => renderCompetitorAd(ad, i))}
               </div>
               <div className="space-y-10">
                  <div className="bg-slate-900 rounded-[3.5rem] p-12 text-white shadow-2xl">
                    <h4 className="text-2xl font-black mb-10 flex items-center gap-4">Winning Elements</h4>
                    {compRes.winning_creative_elements.map((el, i) => (
                      <div key={i} className="flex items-center gap-5 p-5 bg-white/5 rounded-2xl border border-white/10 group hover:bg-white/10 transition-all mb-4">
                        <i className="fas fa-check-circle text-emerald-400 text-sm"></i><p className="text-base font-bold">{el}</p>
                      </div>
                    ))}
                  </div>
               </div>
            </div>
          </div>
        );

      case 'cold':
      case 'warm':
      case 'hot':
      case 'retargeting':
      case 'retention':
        const categoryMap = { cold: 'cold_audience', warm: 'warm_audience', hot: 'hot_audience', retargeting: 'retargeting', retention: 'retention' };
        const category = categoryMap[activeTab as keyof typeof categoryMap] as keyof typeof copies;
        const colorMap = { cold: 'bg-indigo-600', warm: 'bg-orange-600', hot: 'bg-rose-600', retargeting: 'bg-emerald-600', retention: 'bg-pink-600' };
        return (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-700">
            {copies[category].map((piece) => renderContentPiece(piece, colorMap[activeTab as keyof typeof colorMap], category))}
          </div>
        );
      default: return null;
    }
  };

  return (
    <div className="space-y-12 pb-24 max-w-7xl mx-auto px-4 md:px-8">
      {/* Sticky Sub-Navigation */}
      <nav className="flex flex-wrap justify-center gap-4 p-4 bg-white/90 backdrop-blur-xl rounded-[3rem] shadow-2xl border border-slate-100 sticky top-24 z-50 overflow-x-auto no-scrollbar mb-12">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-4 px-8 py-5 rounded-[2rem] text-[13px] font-black transition-all duration-500 whitespace-nowrap shadow-sm border-2 ${
              activeTab === tab.id
                ? `${tab.color} text-white shadow-xl border-transparent scale-105`
                : 'text-slate-500 bg-slate-50 border-slate-100 hover:bg-white hover:text-indigo-600 hover:border-indigo-100'
            }`}
          >
            <i className={`fas ${tab.icon} ${activeTab === tab.id ? 'animate-bounce' : ''}`}></i>
            <span>{tab.label}</span>
          </button>
        ))}
      </nav>
      <div className="min-h-[700px]">
        {renderContent()}
      </div>
    </div>
  );
};

export default AnalysisDashboard;
